section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/external-secrets-operator-recipe.json",
  "type": "object",
  "required": [
    "cluster_secret_store",
    "external_secrets",
    "rbac_scope",
    "alert_on_sync_failure",
    "rotation_test_runbook_path",
    "mount_type"
  ],
  "properties": {
    "cluster_secret_store": {
      "type": "object",
      "description": "object {name, backend, auth_method, identity_ref}"
    },
    "external_secrets": {
      "type": "array",
      "description": "array (each {name, namespace, refresh_interval, target_path, key_refs})"
    },
    "rbac_scope": {
      "type": "string",
      "description": "enum (namespace | cluster_with_approver)"
    },
    "alert_on_sync_failure": {
      "type": "boolean",
      "description": "boolean (true)"
    },
    "rotation_test_runbook_path": {
      "type": "string",
      "description": "string"
    },
    "mount_type": {
      "type": "string",
      "description": "enum (file | env_with_approver)"
    }
  }
}
